def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError(f"desalineado: {len(a)} vs {len(b)}")
    return list(zip(a, b))

try:
    print(zip_strict([1, 2, 3], [10, 20]))
except ValueError as e:
    print("DESALINEADO", e)

print("OK", zip_strict([1, 2], [10, 20]))

