rows = [
    {"id": "C1", "status": "accept"},
    {"id": "C2", "status": "review"},
    {"id": "C3", "status": "reject"},
]
first = -1
first_id = None
for i, r in enumerate(rows):
    if r["status"] == "review":
        first = i
        first_id = r["id"]
        break
if first == -1:
    print(-1)
else:
    print(first, first_id)

